import { useEffect, useState } from "react";


const FantasmaCard = ({ fantasma }) => {
    
  return (
    <>
    <tr>
      <td>{fantasma.nombre}</td>
      <td>Sistema</td>
      <td>Manetta</td>
      <td>Una</td>
      <td>1</td>
    </tr>
    </>
  );
};

export default FantasmaCard;
